import React, { useState, useEffect } from "react";
import ShopPage from "./pages/ShopPage/ShopPage";
import RegisterPage from "./pages/RegisterPage/RegisterPage";
import LoginPage from "./pages/LoginPage/LoginPage";
import { api } from "./api";

export default function App() {
  const [currentPage, setCurrentPage] = useState("shop");
  const [user, setUser] = useState(null);

  // 1. ПРОВЕРКА АВТОРИЗАЦИИ ПРИ ЗАГРУЗКЕ (F5)
  useEffect(() => {
    const checkAuth = async () => {
      const token = localStorage.getItem('token');
      if (token) {
        try {
          const userData = await api.getMe(); 
          setUser(userData);
        } catch (err) {
          localStorage.removeItem('token');
          setUser(null);
        }
      }
    };
    checkAuth();
  }, []);

  const navigateTo = (page) => {
    setCurrentPage(page);
    window.scrollTo(0, 0); 
  };

  // 2. КРАСИВАЯ АВТОРИЗАЦИЯ (Вход -> Токен -> Данные пользователя)
  const handleLoginSuccess = async (token, userData) => {
  localStorage.setItem('token', token);

  // 2. КРИТИЧЕСКИЙ ШАГ: Принудительно обновляем заголовок для текущей сессии
  // Это гарантирует, что следующий запрос (getMe) увидит этот токен
  api.apiClient.defaults.headers.common['Authorization'] = `Bearer ${token}`;

  try {
    // 3. Теперь запрашиваем профиль
    const fullProfile = await api.getMe();
    setUser(fullProfile);
    setIsLoggedIn(true);
    alert(`С возвращением, ${fullProfile.firstName}!`);
  } catch (error) {
    console.error("Ошибка при получении профиля после входа:", error);
    // Если getMe упал, но данные из login у нас есть, можно использовать их как запасной вариант
    setUser(userData);
    setIsLoggedIn(true);
  }
};

  // 3. ВЫХОД (Очистка всего)
  const handleLogout = () => {
    localStorage.removeItem('token');
    setUser(null);
    navigateTo("shop");
  };

  return (
    <div className="app-container">
      {currentPage === "shop" && (
        <ShopPage 
          user={user} 
          onLogout={handleLogout} 
          onNavigate={() => navigateTo("login")} 
        />
      )}

      {currentPage === "register" && (
        <RegisterPage 
          onNavigate={() => navigateTo("login")} 
          onBack={() => navigateTo("shop")}
        />
      )}

      {currentPage === "login" && (
        <LoginPage 
          onNavigate={() => navigateTo("register")} 
          onSuccess={handleLoginSuccess} 
        />
      )}
    </div>
  );
}
